import React, { useEffect, useState } from 'react';
import { api } from '../utils/api';

const colors = {
  bg: colors.bg,
  surface: colors.surface,
  border: '#1F2A37',
  text: '#E5E7DB',
  muted: '#90A3AF',
  green: colors.green,
  red: colors.red,
  blue: colors.blue,
};

const sentimentColors = {
  bullish: colors.green,
  bearish: colors.red,
  neutral: colors.muted,
};

const fallbackNews = [
  {
    title: 'AI Revolutionizes Market Analysis',
    source: 'Aura Alpha',
    sentiment: 'bullish',
    summary:
      'Artificial intelligence is transforming how investors analyze stocks. This new approach promises faster and more accurate insights.',
    timestamp: new Date(Date.now() - 3600 * 1000 * 2).toISOString(),
  },
  {
    title: 'Concerns Over Market Volatility',
    source: 'Aura Alpha',
    sentiment: 'bearish',
    summary:
      'Recent fluctuations have investors worried about potential downturns. Experts advise caution in the coming weeks.',
    timestamp: new Date(Date.now() - 3600 * 1000 * 5).toISOString(),
  },
  {
    title: 'Steady Growth Expected Amid Uncertainty',
    source: 'Aura Alpha',
    sentiment: 'neutral',
    summary:
      'Despite mixed signals, the market shows signs of steady growth. Analysts remain cautiously optimistic about future trends.',
    timestamp: new Date(Date.now() - 3600 * 1000 * 8).toISOString(),
  },
];

function formatTimestamp(isoString) {
  const date = new Date(isoString);
  return date.toLocaleString(undefined, {
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}

export default function TickerNewsDigest({ symbol: propSymbol }) {
  const [symbol, setSymbol] = useState(propSymbol || '');
  const [news, setNews] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // Sync with prop if provided
  useEffect(() => {
    if (propSymbol) setSymbol(propSymbol);
  }, [propSymbol]);

  const fetchNews = async () => {
    if (!symbol) {
      setNews(fallbackNews);
      return;
    }
    setLoading(true);
    setError(null);
    try {
      const data = await api(`/news/${encodeURIComponent(symbol)}`);
      if (!Array.isArray(data)) throw new Error('Invalid data format');
      setNews(data);
    } catch {
      setNews(fallbackNews);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!symbol) {
      setNews(fallbackNews);
      return;
    }
    fetchNews();
  }, [symbol]);

  const displaySymbol = symbol || 'Market';

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono&display=swap');
        .ticker-news-digest {
          font-family: 'JetBrains Mono', monospace;
          background-color: ${colors.bg};
          color: ${colors.text};
          border: 1px solid ${colors.border};
          border-radius: 8px;
          max-width: 720px;
          padding: 12px 16px;
          user-select: none;
        }
        .header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 12px;
        }
        .title {
          font-weight: 700;
          font-size: 1.1rem;
          color: ${colors.blue};
        }
        button.refresh {
          background-color: transparent;
          border: 1px solid ${colors.border};
          border-radius: 4px;
          color: ${colors.muted};
          font-size: 0.85rem;
          padding: 4px 10px;
          cursor: pointer;
          transition: color 0.25s, border-color 0.25s;
        }
        button.refresh:hover {
          color: ${colors.blue};
          border-color: ${colors.blue};
        }
        ul.news-list {
          list-style: none;
          margin: 0;
          padding: 0;
          display: flex;
          flex-direction: column;
          gap: 10px;
        }
        li.news-item {
          background-color: ${colors.surface};
          border: 1px solid ${colors.border};
          border-radius: 6px;
          padding: 10px 14px;
          display: flex;
          flex-direction: column;
          gap: 4px;
          cursor: default;
          transition: background-color 0.15s;
        }
        li.news-item:hover {
          background-color: ${colors.border};
        }
        .news-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          gap: 8px;
          flex-wrap: wrap;
        }
        .news-title {
          font-weight: 600;
          font-size: 0.95rem;
          color: ${colors.text};
          flex: 1 1 auto;
          min-width: 0;
          white-space: nowrap;
          overflow: hidden;
          text-overflow: ellipsis;
        }
        .sentiment-badge {
          font-weight: 700;
          font-size: 0.75rem;
          padding: 2px 8px;
          border-radius: 12px;
          color: ${colors.bg};
          user-select: none;
          flex-shrink: 0;
          text-transform: capitalize;
        }
        .news-source-time {
          font-size: 0.75rem;
          color: ${colors.muted};
          display: flex;
          gap: 8px;
          flex-wrap: wrap;
        }
        .news-summary {
          font-size: 0.85rem;
          color: ${colors.text};
          line-height: 1.3;
          max-height: 3.4em;
          overflow: hidden;
          text-overflow: ellipsis;
        }
        .skeleton {
          background-color: ${colors.border};
          border-radius: 6px;
          height: 72px;
          animation: pulse 1.5s ease-in-out infinite;
        }
        @keyframes pulse {
          0% {
            background-color: ${colors.border};
          }
          50% {
            background-color: ${colors.surface};
          }
          100% {
            background-color: ${colors.border};
          }
        }
        .error-message {
          color: ${colors.red};
          font-size: 0.85rem;
          text-align: center;
          margin-top: 8px;
        }
      `}</style>
      <section className="ticker-news-digest" aria-label={`News digest for ${displaySymbol}`}>
        <div className="header">
          <h2 className="title">{displaySymbol.toUpperCase()} News</h2>
          <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
            {!propSymbol && (
              <input
                type="text"
                placeholder="Symbol..."
                value={symbol}
                onChange={e => setSymbol(e.target.value.toUpperCase())}
                style={{
                  background: colors.surface,
                  border: `1px solid ${colors.border}`,
                  borderRadius: 6,
                  color: colors.text,
                  fontFamily: "'JetBrains Mono', monospace",
                  fontSize: '0.85rem',
                  padding: '4px 8px',
                  width: 80,
                  outline: 'none',
                }}
              />
            )}
            <button
              className="refresh"
              onClick={fetchNews}
              aria-label={`Refresh news for ${displaySymbol}`}
              disabled={loading}
              type="button"
            >
              {loading ? 'Loading...' : 'Refresh'}
            </button>
          </div>
        </div>
        {loading ? (
          <ul className="news-list" aria-busy="true" aria-live="polite">
            {[1, 2, 3].map((n) => (
              <li key={n} className="skeleton" />
            ))}
          </ul>
        ) : news.length > 0 ? (
          <ul className="news-list">
            {news.map(({ title, source, sentiment, summary, timestamp }, i) => (
              <li key={i} className="news-item" tabIndex={0}>
                <div className="news-header">
                  <div className="news-title" title={title}>
                    {title}
                  </div>
                  <div
                    className="sentiment-badge"
                    style={{ backgroundColor: sentimentColors[sentiment] || colors.muted }}
                    aria-label={`Sentiment: ${sentiment}`}
                  >
                    {sentiment}
                  </div>
                </div>
                <div className="news-summary" title={summary}>
                  {summary}
                </div>
                <div className="news-source-time">
                  <span>{source}</span>
                  <span>·</span>
                  <time dateTime={timestamp}>{formatTimestamp(timestamp)}</time>
                </div>
              </li>
            ))}
          </ul>
        ) : (
          <p className="error-message" role="alert">
            No news available.
          </p>
        )}
      </section>
    </>
  );
}
